import React, { useState } from 'react';
import AdminNavbar from '../components/AdminNavbar';
import AdminSidebar from '../components/AdminSidebar';

const ManageCustomers = () => {
  const [customers, setCustomers] = useState([
    { id: 1, name: 'John BR1024', email: 'john@gmail.com', phone: '09453522502', address: 'Tacloban City', status: 'completed', image: 'https://i.imgur.com/9y8ldFB.jpg' },
    { id: 2, name: 'Nino BR1009', email: 'nino@gmail.com', phone: '09173849354', address: 'Tacloban, Leyte', status: 'completed', image: 'https://i.imgur.com/OPSGjvF.jpg' },
    { id: 3, name: 'Jas BR1024', email: 'jas@gmail.com', phone: '09879302345', address: 'Basey, Samar', status: 'failed', image: 'https://i.imgur.com/9y8ldFB.jpg' },
    { id: 4, name: 'Mark BR1035', email: 'mark@gmail.com', phone: '09123456789', address: 'Cebu City', status: 'pending', image: 'https://i.imgur.com/9y8ldFB.jpg' },
    { id: 5, name: 'Anna BR1040', email: 'anna@gmail.com', phone: '09234567890', address: 'Manila', status: 'completed', image: 'https://i.imgur.com/OPSGjvF.jpg' },
    { id: 6, name: 'Ken BR1045', email: 'ken@gmail.com', phone: '09345678901', address: 'Davao', status: 'pending', image: 'https://i.imgur.com/9y8ldFB.jpg' },
    { id: 7, name: 'Lina BR1050', email: 'lina@gmail.com', phone: '09456789012', address: 'Cagayan', status: 'completed', image: 'https://i.imgur.com/OPSGjvF.jpg' },
  ]);

  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [selectedCustomers, setSelectedCustomers] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [editingCustomer, setEditingCustomer] = useState(null);
  const [formData, setFormData] = useState({ name: '', email: '', phone: '', address: '', status: 'completed', image: '' });

  const filteredCustomers = customers.filter(customer => {
    const matchesSearch = customer.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                         customer.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         customer.phone.includes(searchTerm);
    const matchesStatus = !statusFilter || customer.status.toLowerCase() === statusFilter.toLowerCase();
    return matchesSearch && matchesStatus;
  });

  const handleSelectAll = (e) => {
    if (e.target.checked) {
      setSelectedCustomers(filteredCustomers.map(c => c.id));
    } else {
      setSelectedCustomers([]);
    }
  };

  const handleSelectCustomer = (id) => {
    if (selectedCustomers.includes(id)) {
      setSelectedCustomers(selectedCustomers.filter(c => c !== id));
    } else {
      setSelectedCustomers([...selectedCustomers, id]);
    }
  };

  const handleAddCustomer = () => {
    setEditingCustomer(null);
    setFormData({ name: '', email: '', phone: '', address: '', status: 'completed', image: '' });
    setShowModal(true);
  };

  const handleEditCustomer = (customer) => {
    setEditingCustomer(customer);
    setFormData({ ...customer });
    setShowModal(true);
  };

  const handleDeleteCustomer = (id) => {
    setCustomers(customers.filter(c => c.id !== id));
  };

  const handleToggleStatus = (id) => {
    setCustomers(customers.map(c => {
      if (c.id === id) {
        const statuses = ['completed', 'pending', 'failed'];
        const currentIndex = statuses.indexOf(c.status);
        const nextStatus = statuses[(currentIndex + 1) % statuses.length];
        return { ...c, status: nextStatus };
      }
      return c;
    }));
  };

  const handleSaveCustomer = () => {
    if (editingCustomer) {
      setCustomers(customers.map(c => c.id === editingCustomer.id ? { ...formData, id: editingCustomer.id } : c));
    } else {
      setCustomers([...customers, { ...formData, id: Date.now() }]);
    }
    setShowModal(false);
  };

  const handleInputChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const totalCustomers = customers.length;
  const completedCustomers = customers.filter(c => c.status === 'completed').length;
  const pendingCustomers = customers.filter(c => c.status === 'pending').length;
  const failedCustomers = customers.filter(c => c.status === 'failed').length;

  return (
    <div style={styles.container}>
      <AdminNavbar />
      <AdminSidebar />
      
      <main style={styles.mainContent}>
        <div style={styles.contentWrapper}>
          <h2 style={styles.pageTitle}>Manage Customers</h2>

          {/* Top Controls */}
          <div style={styles.topControls}>
            <button style={styles.addBtn} onClick={handleAddCustomer} aria-label="Add new customer">+ Add Customer</button>
            
            <div style={styles.summaryCards} aria-label="Summary of customers">
              <div style={styles.summaryCard} aria-label={`${totalCustomers} Total Customers`}>
                <div style={styles.iconBox}>
                  <svg viewBox="0 0 24 24" style={styles.summaryIcon}>
                    <path d="M3 13h8V3H3v10Zm10 8h8v-6h-8v6ZM3 21h8v-6H3v6ZM13 3v6h8V3h-8Z" fill="white"/>
                  </svg>
                </div>
                <div style={styles.summaryText}>
                  <span style={styles.summaryMain}>{totalCustomers}</span> Total Customers
                </div>
              </div>
              <div style={{...styles.summaryCard, ...styles.summaryCompleted}} aria-label={`${completedCustomers} Completed`}>
                <div style={{...styles.iconBox, backgroundColor: '#529a55'}}>
                  <svg viewBox="0 0 24 24" style={styles.summaryIcon}>
                    <circle cx="12" cy="12" r="10" stroke="white" strokeWidth="2" fill="none"/>
                    <path d="M15 10l4.553-2.276a2 2 0 0 1 2.414 2.819L20 16" stroke="white" strokeWidth="2" fill="none"/>
                  </svg>
                </div>
                <div style={styles.summaryText}>
                  <span style={{...styles.summaryMain, color: '#529a55'}}>{completedCustomers}</span> Completed
                </div>
              </div>
              <div style={{...styles.summaryCard, ...styles.summaryPending}} aria-label={`${pendingCustomers} Pending`}>
                <div style={{...styles.iconBox, backgroundColor: '#c86824'}}>
                  <svg viewBox="0 0 24 24" style={styles.summaryIcon}>
                    <path d="M8 6v3m0 0v3a6 6 0 0 0 12 0v-3m-9-3h6" stroke="white" strokeWidth="2" fill="none" strokeLinecap="round"/>
                  </svg>
                </div>
                <div style={styles.summaryText}>
                  <span style={{...styles.summaryMain, color: '#c86824'}}>{pendingCustomers}</span> Pending
                </div>
              </div>
            </div>
          </div>

          {/* Filters */}
          <div style={styles.filterPanel} role="search" aria-label="Customer filters and search">
            <input 
              type="search" 
              id="searchField"
              placeholder="Search by name, email or phone" 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              style={styles.searchInput}
              aria-label="Search customers by name, email or phone"
            />
            <select 
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
              style={styles.select}
              aria-label="Filter by status"
            >
              <option value="">All Status</option>
              <option value="completed">Completed</option>
              <option value="pending">Pending</option>
              <option value="failed">Failed</option>
            </select>
          </div>

          {/* Table */}
          <div style={styles.tableContainer}>
            <table style={styles.table}>
              <thead>
                <tr>
                  <th style={{...styles.th, ...styles.checkboxCell}}>
                    <input 
                      type="checkbox" 
                      checked={selectedCustomers.length === filteredCustomers.length && filteredCustomers.length > 0}
                      onChange={handleSelectAll}
                      aria-label="Select all customers"
                    />
                  </th>
                  <th style={styles.th}>User</th>
                  <th style={styles.th}>Email</th>
                  <th style={styles.th}>Contact No.</th>
                  <th style={styles.th}>Address</th>
                  <th style={styles.th}>Status</th>
                  <th style={{...styles.th, ...styles.actionsCell}}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredCustomers.map(customer => (
                  <tr key={customer.id} style={styles.tr}>
                    <td style={{...styles.td, ...styles.checkboxCell}}>
                      <input 
                        type="checkbox" 
                        checked={selectedCustomers.includes(customer.id)}
                        onChange={() => handleSelectCustomer(customer.id)}
                        aria-label={`Select ${customer.name}`}
                      />
                    </td>
                    <td style={{...styles.td, ...styles.userCell}}>
                      <img src={customer.image} alt={customer.name} style={styles.userImage} />
                      {customer.name}
                    </td>
                    <td style={styles.td}>{customer.email}</td>
                    <td style={styles.td}>{customer.phone}</td>
                    <td style={styles.td}>{customer.address}</td>
                    <td style={{...styles.td, ...styles.statusCell}}>
                      <span style={{
                        ...styles.statusBadge,
                        ...(customer.status === 'completed' ? styles.statusCompleted : 
                           customer.status === 'pending' ? styles.statusPending : styles.statusFailed)
                      }}>
                        {customer.status}
                      </span>
                    </td>
                    <td style={{...styles.td, ...styles.actionsCell}}>
                      <button 
                        style={styles.actionBtn}
                        onClick={() => handleEditCustomer(customer)}
                        aria-label={`Edit ${customer.name}`}
                      >
                        ✏️
                      </button>
                      <button 
                        style={styles.actionBtn}
                        onClick={() => handleToggleStatus(customer.id)}
                        aria-label={`Change status for ${customer.name}`}
                      >
                        🔄
                      </button>
                      <button 
                        style={styles.actionBtn}
                        onClick={() => handleDeleteCustomer(customer.id)}
                        aria-label={`Delete ${customer.name}`}
                      >
                        🗑️
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {/* Info Row */}
          <section style={styles.infoRow} aria-label="Rental service advantages">
            <div style={styles.infoBox}>
              <svg viewBox="0 0 64 64" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinejoin="round" strokeLinecap="round" style={styles.infoSvg}>
                <path d="M9 52h46M12 44h40M16 36h32M20 28h24M24 20h16"/>
              </svg>
              <div style={styles.infoText}>
                <strong>Affordable Rates</strong>
                <span>Great prices on all vehicle types</span>
              </div>
            </div>
            <div style={styles.infoBox}>
              <svg viewBox="0 0 50 50" fill="none" stroke="currentColor" strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" style={styles.infoSvg}>
                <circle cx="25" cy="25" r="24" />
                <path d="M21 18v9l6 3" />
                <path d="M25 31v-8" />
                <path d="M15 15h20" />
                <path d="M12 38h10" />
                <path d="M33 38h7" />
              </svg>
              <div style={styles.infoText}>
                <strong>Safety &amp; Security</strong>
                <span>Well-maintained and safe rental cars</span>
              </div>
            </div>
            <div style={styles.infoBox}>
              <svg viewBox="0 0 22 22" fill="none" stroke="currentColor" strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" style={styles.infoSvg}>
                <path d="M2 16v1a5 5 0 0 0 10 0v-1" />
                <path d="M17 12v-6a5 5 0 0 0-10 0v6" />
                <line x1="0" y1="7" x2="22" y2="7" />
                <line x1="4" y1="12" x2="18" y2="12" />
                <line x1="7" y1="16" x2="15" y2="16" />
              </svg>
              <div style={styles.infoText}>
                <strong>Easy Booking</strong>
                <span>Quick and hassle free online reservations</span>
              </div>
            </div>
          </section>
        </div>
      </main>

      {/* Modal */}
      {showModal && (
        <div style={styles.modalOverlay} onClick={() => setShowModal(false)}>
          <div style={styles.modal} onClick={e => e.stopPropagation()}>
            <h3 style={styles.modalTitle}>{editingCustomer ? 'Edit Customer' : 'Add New Customer'}</h3>
            <form onSubmit={(e) => { e.preventDefault(); handleSaveCustomer(); }}>
              <div style={styles.formGroup}>
                <label style={styles.label}>Name</label>
                <input 
                  type="text" 
                  name="name" 
                  value={formData.name} 
                  onChange={handleInputChange}
                  style={styles.input}
                  required
                />
              </div>
              <div style={styles.formGroup}>
                <label style={styles.label}>Email</label>
                <input 
                  type="email" 
                  name="email" 
                  value={formData.email} 
                  onChange={handleInputChange}
                  style={styles.input}
                  required
                />
              </div>
              <div style={styles.formGroup}>
                <label style={styles.label}>Phone</label>
                <input 
                  type="tel" 
                  name="phone" 
                  value={formData.phone} 
                  onChange={handleInputChange}
                  style={styles.input}
                  required
                />
              </div>
              <div style={styles.formGroup}>
                <label style={styles.label}>Address</label>
                <input 
                  type="text" 
                  name="address" 
                  value={formData.address} 
                  onChange={handleInputChange}
                  style={styles.input}
                  required
                />
              </div>
              <div style={styles.formGroup}>
                <label style={styles.label}>Status</label>
                <select 
                  name="status" 
                  value={formData.status} 
                  onChange={handleInputChange}
                  style={styles.input}
                >
                  <option value="completed">Completed</option>
                  <option value="pending">Pending</option>
                  <option value="failed">Failed</option>
                </select>
              </div>
              <div style={styles.formGroup}>
                <label style={styles.label}>Image URL</label>
                <input 
                  type="url" 
                  name="image" 
                  value={formData.image} 
                  onChange={handleInputChange}
                  style={styles.input}
                  placeholder="https://..."
                />
              </div>
              <div style={styles.modalButtons}>
                <button type="button" onClick={() => setShowModal(false)} style={styles.cancelBtn}>Cancel</button>
                <button type="submit" style={styles.saveBtn}>Save</button>
              </div>
            </form>
          </div>
        </div>
      )}

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inria+Serif&display=swap');
        
        * { box-sizing: border-box; }
      `}</style>
    </div>
  );
};

