  },
  select: {
    padding: '7px 11px',
    fontWeight: 600,
    fontSize: '13.8px',
    borderRadius: '9px',
    border: '1px solid #c7c7c7',
    backgroundColor: 'white',
    color: '#515151',
    fontFamily: 'Inria Serif, serif',
  },
  tableContainer: {
    background: 'white',
    borderRadius: '8px',
    boxShadow: '0 2px 8px #66678840',
    overflow: 'auto',
  },
  table: {
    borderCollapse: 'collapse',
    width: '100%',
    fontFamily: 'Inria Serif, serif',
  },
  th: {
    whiteSpace: 'nowrap',
    padding: '10px 15px',
    fontWeight: 600,
    fontSize: '13.9px',
    color: '#2b2f57',
    textAlign: 'left',
    backgroundColor: '#d6def9',
    borderBottom: '3px solid #2334ac',
  },
  td: {
    padding: '9.8px 15px',
