  },
  infoRow: {
    display: 'flex',
    justifyContent: 'space-between',
    marginTop: '36px',
    backgroundColor: 'white',
    padding: '18px 28px',
    borderRadius: '8px',
    boxShadow: '0 2px 6px #9999993a',
    gap: '20px',
  },
  infoBox: {
    display: 'flex',
